using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    #region CalculateTotal — DataRow (inline values)

    [TestMethod]
    [DataRow(10.00, 2, 0.10, 22.00, DisplayName = "Basic with 10% tax")]
    [DataRow(5.50, 4, 0.0, 22.00, DisplayName = "Zero tax")]
    [DataRow(100.00, 1, 0.25, 125.00, DisplayName = "Single item 25% tax")]
    [DataRow(9.99, 3, 0.08, 32.37, DisplayName = "Fractional price 8% tax")]
    [DataRow(0.00, 5, 0.15, 0.00, DisplayName = "Zero price")]
    [DataRow(50.00, 0, 0.10, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    #endregion

    #region CalculateTotal — invalid inputs

    [TestMethod]
    [DataRow(-1.00, 2, 0.10, DisplayName = "Negative unit price")]
    public void CalculateTotal_NegativeUnitPrice_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity")]
    public void CalculateTotal_NegativeQuantity_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, 2, -0.01, DisplayName = "Tax rate below 0")]
    [DataRow(10.00, 2, 1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    #endregion

    #region ApplyDiscount — DynamicData with ValueTuples

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsDiscountedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),
        (80m, 100m, 0m),
        (99.99m, 50m, 49.995m),
    ];

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Discount below 0%")]
    [DataRow(100.1, DisplayName = "Discount above 100%")]
    public void ApplyDiscount_InvalidPercent_Throws(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }

    #endregion

    #region FormatPrice — DataRow

    [TestMethod]
    [DataRow(9.99, "$", "$9.99", DisplayName = "Default dollar")]
    [DataRow(1234.5, "€", "€1234.50", DisplayName = "Euro symbol")]
    [DataRow(0.0, "£", "£0.00", DisplayName = "Zero pounds")]
    public void FormatPrice_WithSymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }

    #endregion
}

